def _read_csv_autoindex(path):
    """
    Robust CSV reader: auto-detects the date column regardless of whether
    the header is literally 'Date' or an unnamed first column (Unnamed: 0).
    Fixes crash when features.csv was saved without explicit index name.
    """
    df = pd.read_csv(path)
    date_col = df.columns[0]                      # first column is always the date
    df[date_col] = pd.to_datetime(df[date_col], errors="coerce")
    df = df.set_index(date_col)
    df.index.name = "Date"
    df = df.apply(pd.to_numeric, errors="coerce")
    return df[df.index.notna()].sort_index()


