def human_col_label(col):
    """Convert technical column names to human-readable labels."""
    if col in INDICATOR_LABELS:
        return INDICATOR_LABELS[col]
    # Try country_indicator pattern
    for country_key, country_name in COUNTRY_SHORT.items():
        if col.startswith(country_key + "_"):
            suffix = col[len(country_key)+1:]
            ind = INDICATOR_LABELS.get(suffix, suffix.replace("_"," ").title())
            return f"{country_name}  {ind}"
    # Fallback: clean up underscores
    return col.replace("_"," ").replace("  "," ").title()

