NEWS_FEEDS = [
    ("Reuters Markets", "https://feeds.reuters.com/reuters/businessNews"),
    ("FT Emerging Markets", "https://www.ft.com/emerging-markets?format=rss"),
    ("Bloomberg Markets", "https://feeds.bloomberg.com/markets/news.rss"),
    ("Economic Times", "https://economictimes.indiatimes.com/markets/rssfeeds/1977021501.cms"),
]

# Keywords to filter BRICS-relevant news
BRICS_KEYWORDS = [
    "brazil","russia","india","china","south africa","brics","emerging market",
    "rupee","ruble","yuan","renminbi","real","rand","fed rate","dollar","inflation",
    "gdp","currency","reserve bank","rbi","pboc","imf","world bank",
]

news_cache = []
news_last_updated = [0]


def fetch_news():
    """Fetch news from RSS feeds and filter for BRICS relevance."""
    try:
        import feedparser
    except ImportError:
        return [{"title":"Install feedparser: pip install feedparser",
                 "link":"#","source":"System","time":"now","snippet":""}]

    articles = []
    for source_name, url in NEWS_FEEDS:
        try:
            feed = feedparser.parse(url)
            for entry in feed.entries[:8]:
                title   = getattr(entry, "title",   "")
                summary = getattr(entry, "summary", "")
                link    = getattr(entry, "link",    "#")
                pub     = getattr(entry, "published","")
                combined = (title + " " + summary).lower()
                if any(kw in combined for kw in BRICS_KEYWORDS):
                    articles.append({
                        "title":   title[:120],
                        "snippet": summary[:200].replace("<p>","").replace("</p>","").strip(),
                        "link":    link,
                        "source":  source_name,
                        "time":    pub[:16] if pub else "",
                    })
        except Exception:
            continue

    # Deduplicate by title
    seen = set()
    unique = []
    for a in articles:
        if a["title"] not in seen:
            seen.add(a["title"]); unique.append(a)
    return unique[:20] if unique else [
        {"title":"No live news available  check internet connection",
         "link":"#","source":"System","time":"","snippet":"Run with internet access to see live BRICS headlines"}
    ]


def refresh_news_background():
    """Refresh news cache every 10 minutes in background thread."""
    while True:
        try:
            news_cache.clear()
            news_cache.extend(fetch_news())
            news_last_updated[0] = time.time()
        except Exception:
            pass
        time.sleep(600)


# Start background news thread
news_thread = threading.Thread(target=refresh_news_background, daemon=True)
news_thread.start()

