def fit_elasticity_models(df):
    models = {}
    if "DXY_mom_12m" not in df.columns: return models
    for country in BRICS:
        col = country + "_depr_12m"
        if col not in df.columns: continue
        tmp = df[[col,"DXY_mom_12m"]].dropna()
        if len(tmp)<20: continue
        reg = LinearRegression()
        reg.fit(tmp[["DXY_mom_12m"]], tmp[col])
        ss_res = ((tmp[col]-reg.predict(tmp[["DXY_mom_12m"]]))**2).sum()
        ss_tot = ((tmp[col]-tmp[col].mean())**2).sum()
        r2 = 1-ss_res/ss_tot if ss_tot>0 else 0
        models[country] = {"beta":round(float(reg.coef_[0]),4),
                           "alpha":round(float(reg.intercept_),4),
                           "r2":round(r2,3),
                           "hist_mean":round(float(tmp[col].mean()),2),
                           "hist_std":round(float(tmp[col].std()),2)}
    return models


