# PRE-COMPUTE: Crisis metrics
# =============================================================================

def compute_crisis_metrics(df):
    metrics = {}
    for country in ALL_COUNTRIES:
        col = country+"_depr_12m"
        if col not in df.columns: continue
        series = df[col].dropna()
        if len(series)<4: continue
        latest  = float(series.iloc[-1])
        prev_3m = float(series.iloc[-4]) if len(series)>=4 else latest
        change  = latest-prev_3m
        if latest>15 or change>8:   level="CRITICAL"
        elif latest>8 or change>4:  level="WARNING"
        elif latest>3:              level="WATCH"
        else:                       level="STABLE"
        crisis_mask = series>10; crisis_periods = []; in_crisis=False; start=None
        for date,is_crisis in crisis_mask.items():
            if is_crisis and not in_crisis:   in_crisis=True; start=date
            elif not is_crisis and in_crisis: in_crisis=False; crisis_periods.append((start,date))
        if in_crisis: crisis_periods.append((start,series.index[-1]))
        metrics[country] = {"latest":round(latest,2),"change_3m":round(change,2),
                            "level":level,"crisis_periods":crisis_periods,"series":series}
    return metrics


