def find_fund_col(country, indicator, df_cols):
    """Try multiple column name patterns and return the first one that exists."""
    for suffix in FUND_COL_ALIASES.get(indicator, [indicator]):
        col = f"{country}_{suffix}"
        if col in df_cols:
            return col
    return None

