def card(title, children, extra_header=None):
    header = [html.P(title, className="dh-card-title")]
    if extra_header:
        header.append(extra_header)
    return dbc.Card(dbc.CardBody(header+list(children)), className="dh-card")


def stat_box(value, label):
    return html.Div([html.Span(value,className="dh-stat-value"),html.Span(label,className="dh-stat-label")],className="dh-stat-box")


def date_range_slider(slider_id, label="DATE RANGE"):
    # Build year marks every 2 years so axis is clean and readable
    marks = {}
    year = DATE_MIN.year
    while year <= DATE_MAX.year:
        idx = (year - DATE_MIN.year) * 12
        idx = min(idx, TOTAL_MONTHS)
        marks[idx] = {
            "label": str(year),
            "style": {"color":"#475569","fontFamily":"Space Mono","fontSize":"9px"},
        }
        year += 2

    return html.Div([
        html.Span(label, className="dh-range-label"),
        # Live date display row  updates via callback
        dbc.Row([
            dbc.Col(html.Span(id=slider_id+"-start-lbl",
                style={"fontFamily":"Space Mono","fontSize":"10px","color":"#f0c040",
                       "display":"block","textAlign":"left"}), width=6),
            dbc.Col(html.Span(id=slider_id+"-end-lbl",
                style={"fontFamily":"Space Mono","fontSize":"10px","color":"#f0c040",
                       "display":"block","textAlign":"right"}), width=6),
        ], className="mb-1"),
        dcc.RangeSlider(
            id=slider_id, min=0, max=TOTAL_MONTHS, step=1,
            value=[0, TOTAL_MONTHS],
            marks=marks,
            tooltip={"always_visible": False, "placement": "bottom"},
            updatemode="mouseup",
        ),
    ], className="dh-range-row")


def download_btn(btn_id, label="DOWNLOAD CSV", style_class="dh-btn"):
    return html.A(label, id=btn_id, className=style_class,
                  download="data.csv", href="", target="_blank",
                  style={"marginRight":"8px"})


