# =============================================================================
# HELPER: filter df by date range slider
# =============================================================================

def slice_df(df, range_val):
    if not range_val or len(range_val) < 2:
        return df
    start = idx_to_date(range_val[0])
    end   = idx_to_date(range_val[1])
    return df[(df.index >= start) & (df.index <= end)]


# Slider label callbacks  shows "Jan 2005  Dec 2020" above each slider
@app.callback(
    Output("macro-date-range-start-lbl","children"),
    Output("macro-date-range-end-lbl","children"),
    Input("macro-date-range","value"))
def update_macro_slider_labels(range_val):
    if not range_val or len(range_val) < 2:
        return str(DATE_MIN.strftime("%b %Y")), str(DATE_MAX.strftime("%b %Y"))
    s = idx_to_date(range_val[0]).strftime("%b %Y")
    e = idx_to_date(range_val[1]).strftime("%b %Y")
    return s, e


@app.callback(
    Output("fund-date-range-start-lbl","children"),
    Output("fund-date-range-end-lbl","children"),
    Input("fund-date-range","value"))
def update_fund_slider_labels(range_val):
    if not range_val or len(range_val) < 2:
        return str(DATE_MIN.strftime("%b %Y")), str(DATE_MAX.strftime("%b %Y"))
    s = idx_to_date(range_val[0]).strftime("%b %Y")
    e = idx_to_date(range_val[1]).strftime("%b %Y")
    return s, e


