@app.callback(Output("chart-dxy","figure"), Input("group-selector","value"), Input("macro-date-range","value"))
def update_dxy(_, range_val):
    dff = slice_df(df, range_val)
    if "DXY" not in dff.columns: return go.Figure()
    fig = go.Figure()
    fig.add_trace(go.Scatter(x=dff.index,y=dff["DXY"],mode="lines",name="DXY",
        line=dict(color="#f0c040",width=1.8),fill="tozeroy",fillcolor="rgba(240,192,64,0.04)"))
    for ed,lbl in [("2008-09","GFC"),("2020-03","COVID"),("2022-02","Ukraine")]:
        try:
            x=pd.Timestamp(ed)
            if dff.index.min()<=x<=dff.index.max():
                fig.add_vline(x=x,line_dash="dot",line_color="rgba(248,113,113,0.45)",line_width=1)
                fig.add_annotation(x=x,y=dff["DXY"].max(),text=lbl,showarrow=False,font=dict(color="#f87171",size=9,family="Space Mono"),yshift=6)
        except: pass
    fig.update_layout(**{**CHART_LAYOUT,"yaxis_title":"DXY"})
    return fig


