@app.callback(Output("chart-scatter","figure"), Input("x-axis-col","value"), Input("y-axis-col","value"), Input("macro-date-range","value"))
def update_scatter(xc,yc,range_val):
    if not xc or not yc: return _empty_fig("Select columns above")
    dff=slice_df(df,range_val); tmp=dff[[xc,yc]].dropna()
    if len(tmp)<5: return _empty_fig("Not enough data")
    corr=round(tmp.corr().iloc[0,1],3)
    xv=tmp[xc].values; yv=tmp[yc].values; z=np.polyfit(xv,yv,1); xl=np.linspace(xv.min(),xv.max(),100)
    fig=go.Figure(); fig.add_trace(go.Scatter(x=xv,y=yv,mode="markers",marker=dict(size=5,opacity=0.55,color="#5b9cf6"),name="Data")); fig.add_trace(go.Scatter(x=xl,y=np.poly1d(z)(xl),mode="lines",line=dict(color="#f0c040",width=1.5,dash="dot"),name="Trend"))
    fig.update_layout(**{**CHART_LAYOUT,"title":dict(text=f"r = {corr}",font=dict(family="Space Mono",size=11,color="#f0c040"),x=0.02),"margin":dict(l=44,r=16,t=36,b=40)})
    return fig


