@app.callback(Output("sim-dxy-slider","value"), Output("sim-mom-slider","value"),
              Input("btn-strong","n_clicks"), Input("btn-current","n_clicks"), Input("btn-weak","n_clicks"),
              prevent_initial_call=True)
def preset_buttons(n1,n2,n3):
    from dash import ctx
    t=ctx.triggered_id
    if t=="btn-strong":  return dxy_current*1.15,15.0
    elif t=="btn-weak":  return dxy_current*0.85,-15.0
    else:                return dxy_current,current_dxy_mom


def compute_impacts(dxy_mom):
    results={}
    for country in BRICS:
        if country not in elasticity: results[country]={"projected":0.0,"vs_baseline":0.0,"beta":0,"r2":0,"hist_mean":0,"hist_std":0}; continue
        e=elasticity[country]; proj=e["alpha"]+e["beta"]*dxy_mom; baseline=e["alpha"]+e["beta"]*current_dxy_mom
        results[country]={"projected":round(proj,2),"vs_baseline":round(proj-baseline,2),"beta":e["beta"],"r2":e["r2"],"hist_mean":e["hist_mean"],"hist_std":e["hist_std"]}
    return results


@app.callback(Output("sim-scenario-strip","children"), Output("sim-impact-cards","children"),
              Output("chart-sensitivity","figure"), Output("chart-sim-bar","figure"),
              Input("sim-dxy-slider","value"), Input("sim-mom-slider","value"))
def update_simulator(dxy_level,dxy_mom):
    impacts=compute_impacts(dxy_mom)
    if dxy_mom>8:    zone_label,zone_cls,zone_desc="STRONG DOLLAR","zone-high","Dollar strengthening  BRICS currencies under pressure"
    elif dxy_mom<-8: zone_label,zone_cls,zone_desc="WEAK DOLLAR","zone-low","Dollar weakening  relief for emerging market currencies"
    else:            zone_label,zone_cls,zone_desc="NEUTRAL","zone-medium","Dollar range-bound  moderate pressure on BRICS"
    strip=dbc.Row([dbc.Col([html.Div([
        html.Span(f"DXY: {dxy_level:.1f}",style={"fontFamily":"Space Mono","fontSize":"13px","color":"#f0c040","marginRight":"20px","fontWeight":"700"}),
        html.Span(f"MOMENTUM: {dxy_mom:+.1f}%",style={"fontFamily":"Space Mono","fontSize":"13px","color":"#94a3b8","marginRight":"20px"}),
        html.Span(zone_label,className=f"scenario-zone {zone_cls}",style={"marginRight":"16px"}),
        html.Span(zone_desc,style={"fontFamily":"DM Sans","fontSize":"11px","color":"#64748b"}),
    ],style={"background":"#0a0f1c","border":"1px solid rgba(99,179,237,0.12)","borderRadius":"8px","padding":"12px 18px","display":"flex","alignItems":"center","flexWrap":"wrap","gap":"4px"})],width=12)])
    max_abs=max(abs(v["projected"]) for v in impacts.values()) or 1
    card_cols=[]
    for country in BRICS:
        imp=impacts[country]; proj=imp["projected"]; delta=imp["vs_baseline"]
        color=BRICS_COLORS.get(country,"#aaa"); bar_pct=min(100,abs(proj)/max_abs*100)
        delta_str=f"{delta:+.1f}% vs now"; delta_color="#f87171" if delta>0.5 else "#34d399" if delta<-0.5 else "#94a3b8"
        card_cols.append(dbc.Col([html.Div([
            html.Span(country.replace("_"," "),className="impact-card-country"),
            html.Span(f"{proj:+.1f}%",className="impact-card-value",style={"color":"#f87171" if proj>5 else "#fbbf24" if proj>2 else "#34d399"}),
            html.Span("projected 12m depreciation",className="impact-card-sublabel"),
            html.Span(delta_str,style={"fontFamily":"Space Mono","fontSize":"10px","color":delta_color,"marginTop":"4px","display":"block"}),
            html.Span(f"beta={imp['beta']:+.3f}  r={imp['r2']:.2f}",className="impact-card-beta"),
            html.Div(className="impact-card-bar",children=[html.Div(className="impact-card-bar-fill",style={"width":f"{bar_pct:.0f}%","background":color})]),
        ],className="impact-card",style={"borderColor":color+"44"})],width=12//len(BRICS)))
    cards=dbc.Row(card_cols,className="g-2")
    x_range=np.linspace(-20,20,80)
    fig_sens=go.Figure()
    for country in BRICS:
        if country not in elasticity: continue
        e=elasticity[country]
        fig_sens.add_trace(go.Scatter(x=x_range,y=e["alpha"]+e["beta"]*x_range,mode="lines",name=country.replace("_"," "),line=dict(color=BRICS_COLORS.get(country,"#aaa"),width=1.8)))
    fig_sens.add_vline(x=dxy_mom,line_dash="dot",line_color="rgba(240,192,64,0.7)",line_width=2)
    fig_sens.add_annotation(x=dxy_mom,y=0.98,yref="paper",text=f"SCENARIO\n{dxy_mom:+.1f}%",showarrow=False,font=dict(color="#f0c040",size=9,family="Space Mono"),xanchor="left" if dxy_mom<10 else "right")
    fig_sens.add_vline(x=current_dxy_mom,line_dash="dot",line_color="rgba(148,163,184,0.3)",line_width=1)
    fig_sens.update_layout(**{**CHART_LAYOUT,"xaxis_title":"DXY 12M Momentum (%)","yaxis_title":"Projected Depreciation (%)","margin":dict(l=44,r=16,t=16,b=44)})
    proj_vals=[impacts[c]["projected"] for c in BRICS]
    fig_bar=go.Figure()
    fig_bar.add_trace(go.Bar(x=[c.replace("_"," ") for c in BRICS],y=proj_vals,marker=dict(color=[BRICS_COLORS.get(c,"#aaa") for c in BRICS],opacity=0.85,line=dict(color="rgba(0,0,0,0)")),text=[f"{v:+.1f}%" for v in proj_vals],textposition="outside",textfont=dict(family="Space Mono",size=10,color="#94a3b8")))
    fig_bar.add_hline(y=0,line_dash="dot",line_color="rgba(148,163,184,0.25)",line_width=1)
    fig_bar.update_layout(**{**CHART_LAYOUT,"yaxis_title":"Projected Depreciation (%)","showlegend":False,"bargap":0.3,"margin":dict(l=44,r=16,t=16,b=40)})
    return strip,cards,fig_sens,fig_bar


