@app.callback(Output("chart-world-map","figure"), Input("map-metric","value"), Input("map-period","value"))
def update_world_map(metric,period):
    records=[]
    for country in ALL_COUNTRIES:
        col=country+"_depr_12m"
        if col not in df.columns: continue
        series=df[col].dropna()
        if series.empty: continue
        val=float(series.iloc[-1]) if period=="latest" else float(series.iloc[-12:].mean()) if period=="1y" and len(series)>=12 else float(series.iloc[-60:].mean()) if period=="5y" and len(series)>=60 else float(series.mean())
        iso=COUNTRY_ISO.get(country)
        if not iso: continue
        alert_num={"STABLE":0,"WATCH":1,"WARNING":2,"CRITICAL":3}.get(crisis_metrics.get(country,{}).get("level","STABLE"),0)
        records.append({"country":country,"iso":iso,"name":COUNTRY_FULL.get(country,country),"depr":round(val,2),"alert_num":alert_num,"level":crisis_metrics.get(country,{}).get("level","STABLE")})
    map_df=pd.DataFrame(records)
    if map_df.empty: return go.Figure()
    color_col="depr" if metric=="depr" else "alert_num"
    color_scale="RdYlGn_r" if metric=="depr" else [[0,"#34d399"],[0.33,"#60a5fa"],[0.66,"#fbbf24"],[1,"#f87171"]]
    fig=px.choropleth(map_df,locations="iso",color=color_col,hover_name="name",hover_data={"depr":True,"level":True,"iso":False,"alert_num":False},color_continuous_scale=color_scale,labels={"depr":"Depreciation (%)","level":"Alert","alert_num":"Alert Level"})
    fig.update_traces(marker_line_color="rgba(99,179,237,0.2)",marker_line_width=0.5,hovertemplate="<b>%{hovertext}</b><br>Depreciation: %{customdata[0]:.1f}%<br>Alert: %{customdata[1]}<extra></extra>")
    fig.update_layout(paper_bgcolor="rgba(0,0,0,0)",plot_bgcolor="rgba(0,0,0,0)",
        geo=dict(bgcolor="rgba(0,0,0,0)",landcolor="#0f1621",oceancolor="#080c14",showocean=True,showland=True,showcountries=True,countrycolor="rgba(99,179,237,0.1)",showframe=False,coastlinecolor="rgba(99,179,237,0.15)",lakecolor="#080c14",projection_type="natural earth"),
        coloraxis_colorbar=dict(title=dict(text="Depreciation (%)" if metric=="depr" else "Alert",font=dict(family="Space Mono",size=9,color="#94a3b8")),tickfont=dict(family="Space Mono",size=9,color="#94a3b8"),bgcolor="rgba(13,18,32,0.8)",bordercolor="rgba(99,179,237,0.2)",thickness=12),
        margin=dict(l=0,r=0,t=0,b=0),font=dict(family="DM Sans",color="#94a3b8"))
    return fig


