            dbc.Col([html.Div([html.Span(str(len(m['crisis_periods'])),style={"fontFamily":"Space Mono","fontSize":"22px","fontWeight":"700","color":"#fbbf24","display":"block"}),html.Span("CRISIS PERIODS",style={"fontFamily":"Space Mono","fontSize":"9px","letterSpacing":"0.12em","color":"#64748b","display":"block","marginTop":"3px"})],style=stat_style)],width=3),
