    fig.add_hrect(y0=0,y1=40,fillcolor="rgba(52,211,153,0.06)",line_width=0)
    fig.add_hrect(y0=40,y1=65,fillcolor="rgba(251,191,36,0.06)",line_width=0)
    fig.add_hrect(y0=65,y1=100,fillcolor="rgba(248,113,113,0.06)",line_width=0)
    for (s,e,lbl) in [("2008-06","2009-06","GFC"),("2014-06","2016-06","EM Crisis"),("2020-01","2020-12","COVID"),("2022-02","2023-06","Ukraine")]:
        try: fig.add_vrect(x0=pd.Timestamp(s),x1=pd.Timestamp(e),fillcolor="rgba(248,113,113,0.06)",line_width=0); fig.add_annotation(x=pd.Timestamp(s),y=95,text=lbl,showarrow=False,font=dict(color="#f87171",size=8,family="Space Mono"),xanchor="left")
        except: pass
    fig.add_trace(go.Scatter(x=dsi.index,y=dsi.values,mode="lines",name="DSI",line=dict(color="#e8edf5",width=1.5),fill="tozeroy",fillcolor="rgba(240,192,64,0.03)"))
    fig.add_hline(y=65,line_dash="dot",line_color="rgba(248,113,113,0.55)",line_width=1,annotation_text="CRISIS THRESHOLD",annotation_font=dict(size=9,color="#f87171",family="Space Mono"),annotation_position="top right")
    fig.update_layout(**{**CHART_LAYOUT,"yaxis":dict(range=[0,100],title="DSI Score",showgrid=True,gridcolor="rgba(99,179,237,0.05)",tickfont=dict(size=10,color="#475569")),"showlegend":False})
    return fig


