@app.callback(Output("fund-stat-cards","children"),
              Input("fund-indicator","value"), Input("fund-countries","value"), Input("fund-date-range","value"))
def update_fund_stat_cards(indicator, countries, range_val):
    if not countries: return html.Div()
    dff = slice_df(df, range_val)
    cards = []
    ind_label, ind_unit, ind_color = FUND_INDICATORS.get(indicator, (indicator, "", "#5b9cf6"))
    for country in countries:
        col = find_fund_col(country, indicator, dff.columns)
        if col is None: continue
        series = dff[col].dropna()
        if series.empty: continue
        latest = float(series.iloc[-1])
        color = BRICS_COLORS.get(country, "#5b9cf6")
        val_color = "#f87171" if (indicator in ("Debt_to_GDP","CPI_inflation") and latest > 60) else "#34d399" if latest > 0 else "#f87171"
        cards.append(dbc.Col([html.Div([
            html.Span(f"{latest:.1f} {ind_unit}", className="fund-value", style={"color": val_color}),
            html.Span(country.replace("_"," "), className="fund-label"),
            html.Span(ind_label, style={"fontFamily":"Space Mono","fontSize":"8px","color":"#475569","letterSpacing":"0.1em","textTransform":"uppercase","display":"block","marginTop":"3px"}),
        ], className="fund-card", style={"borderLeft": f"3px solid {color}"})], width=12//len(countries)))

    if not cards:
        return html.Div([
            html.Span(" No fundamental data found for this indicator.",
                style={"fontFamily":"Space Mono","fontSize":"10px","color":"#f87171",
                       "display":"block","padding":"10px 0"}),
            html.Span("Run data_collector_v2.py then feature_engineer_v2.py to load World Bank data.",
                style={"fontFamily":"Space Mono","fontSize":"9px","color":"#475569","display":"block"}),
        ])
    return dbc.Row(cards, className="g-2 mb-2")


@app.callback(Output("chart-fundamentals","figure"),
              Input("fund-indicator","value"), Input("fund-countries","value"), Input("fund-date-range","value"))
def update_fundamentals(indicator, countries, range_val):
    fig = go.Figure()
    if not countries:
        return fig
    dff = slice_df(df, range_val)
    ind_label, ind_unit, _ = FUND_INDICATORS.get(indicator, (indicator, "", "#aaa"))
    has_data = False
    for country in countries:
        col = find_fund_col(country, indicator, dff.columns)
        if col is None:
            continue
        series = dff[col].dropna()
        if series.empty:
            continue
        has_data = True
        color = BRICS_COLORS.get(country, "#aaa")
        fig.add_trace(go.Scatter(x=series.index, y=series.values, mode="lines",
            name=country.replace("_"," "), line=dict(color=color, width=2)))
    fig.add_hline(y=0, line_dash="dot", line_color="rgba(148,163,184,0.2)", line_width=1)
    if not has_data:
        fig.add_annotation(
            text="No data  run data_collector_v2.py then feature_engineer_v2.py",
            xref="paper", yref="paper", x=0.5, y=0.5, showarrow=False,
            font=dict(color="#475569", size=12, family="Space Mono"),
        )
    fig.update_layout(**{**CHART_LAYOUT, "yaxis_title": f"{ind_label} ({ind_unit})"})
    return fig


@app.callback(Output("dl-fund-csv","href"),
              Input("fund-indicator","value"), Input("fund-countries","value"), Input("fund-date-range","value"))
def dl_fund(indicator, countries, range_val):
    if not countries: return ""
    dff = slice_df(df, range_val)
    cols = [find_fund_col(c, indicator, dff.columns) for c in countries]
    cols = [c for c in cols if c is not None]
    if not cols: return ""
    csv = dff[cols].to_csv()
    return "data:text/csv;charset=utf-8,"+csv.replace("\n","%0A").replace(",","%2C")


@app.callback(Output("chart-stocks","figure"), Input("fund-date-range","value"))
def update_stocks(range_val):
    fig = go.Figure()
    dff = slice_df(df, range_val)
    has_data = False
    for col, (label, color) in STOCK_COLS.items():
        if col not in dff.columns: continue
        series = dff[col].dropna()
        if series.empty: continue
        has_data = True
        # Normalize to 100 at start for comparison
        base = float(series.iloc[0]) if float(series.iloc[0]) != 0 else 1
        normalized = series / base * 100
        fig.add_trace(go.Scatter(x=series.index, y=normalized.values, mode="lines",
            name=label, line=dict(color=color, width=1.8)))
    fig.add_hline(y=100, line_dash="dot", line_color="rgba(148,163,184,0.2)", line_width=1)
    if not has_data:
        fig.add_annotation(
            text="No stock data  run data_collector_v2.py to load BRICS stock indices",
            xref="paper", yref="paper", x=0.5, y=0.5, showarrow=False,
            font=dict(color="#475569", size=12, family="Space Mono"),
        )
    fig.update_layout(**{**CHART_LAYOUT, "yaxis_title": "Indexed (base=100)"})
    return fig


@app.callback(Output("dl-stocks-csv","href"), Input("fund-date-range","value"))
def dl_stocks(range_val):
    dff = slice_df(df, range_val)
    cols = [c for c in STOCK_COLS if c in dff.columns]
    if not cols: return ""
    csv = dff[cols].to_csv()
    return "data:text/csv;charset=utf-8,"+csv.replace("\n","%0A").replace(",","%2C")


@app.callback(Output("chart-fund-scatter","figure"),
              Input("fund-scatter-x","value"), Input("fund-scatter-y","value"), Input("fund-date-range","value"))
def update_fund_scatter(xc, yc, range_val):
    if not xc or not yc: return go.Figure()
    dff = slice_df(df, range_val)
    # xc is stored as "Country_indicator" (e.g. "Brazil_GDP_growth")
    # resolve to actual column via alias if needed
    def resolve_col(raw):
        if raw in dff.columns:
            return raw
        # try parsing as country + indicator
        for country in BRICS:
            if raw.startswith(country + "_"):
                indicator = raw[len(country)+1:]
                resolved = find_fund_col(country, indicator, dff.columns)
                if resolved:
                    return resolved
        return None
    xc_real = resolve_col(xc)
    yc_real = resolve_col(yc)
    if not xc_real or not yc_real:
        fig = go.Figure()
        fig.add_annotation(text="No data  run data_collector_v2.py first",
            xref="paper", yref="paper", x=0.5, y=0.5, showarrow=False,
            font=dict(color="#475569", size=12, family="Space Mono"))
        fig.update_layout(**CHART_LAYOUT)
        return fig
    tmp = dff[[xc_real, yc_real]].dropna()
    if len(tmp) < 5:
        return _empty_fig("Run data_collector_v2.py first")
    corr = round(tmp.corr().iloc[0,1], 3)
    xv2=tmp[xc_real].values; yv2=tmp[yc_real].values; z2=np.polyfit(xv2,yv2,1); xl2=np.linspace(xv2.min(),xv2.max(),100)
    fig=go.Figure(); fig.add_trace(go.Scatter(x=xv2,y=yv2,mode="markers",marker=dict(size=5,opacity=0.55,color="#a78bfa"),name="Data")); fig.add_trace(go.Scatter(x=xl2,y=np.poly1d(z2)(xl2),mode="lines",line=dict(color="#f0c040",width=1.5,dash="dot"),name="Trend"))
    fig.update_layout(**{**CHART_LAYOUT,"title":dict(text=f"r = {corr}",font=dict(family="Space Mono",size=11,color="#f0c040"),x=0.02),"margin":dict(l=44,r=16,t=36,b=40)})
    return fig


