@app.callback(Output("news-feed-content","children"), Input("news-refresh-btn","n_clicks"), Input("main-tabs","active_tab"))
def update_news(n_clicks, active_tab):
    if active_tab != "tab-news" and not n_clicks:
        return html.Div()

    articles = news_cache if news_cache else fetch_news()

    if not articles:
        return html.P("No articles found.", style={"color":"#475569","fontFamily":"Space Mono","fontSize":"11px"})

    cards = []
    for a in articles[:15]:
        cards.append(html.Div([
            html.A(a["title"], href=a["link"], target="_blank",
                   style={"textDecoration":"none","color":"inherit"}),
            html.P(className="news-meta", children=[
                html.Span(a["source"], style={"color":"#5b9cf6"}),
                html.Span("    " + a["time"] if a["time"] else "", style={"color":"#475569"}),
            ]),
            *([html.P(a["snippet"][:160]+"...", className="news-snippet")] if a.get("snippet") else []),
        ], className="news-card"))

    return html.Div(cards)


@app.callback(Output("macro-snapshot","children"), Input("main-tabs","active_tab"))
def update_macro_snapshot(_):
    items = []
    snapshot_data = [
        ("DXY Index",    "DXY",         "#f0c040", "{:.1f}"),
        ("DSI Score",    "DSI",         "#f87171", "{:.0f}"),
        ("WTI Oil",      "Oil_WTI",     "#fb923c", "${:.0f}"),
        ("US Fed Rate",  "US_Fed_Rate", "#5b9cf6", "{:.2f}%"),
        ("US CPI YoY",   "US_CPI_yoy",  "#a78bfa", "{:.1f}%"),
    ]
    for label, col, color, fmt in snapshot_data:
        if col not in df.columns: continue
        series = df[col].dropna()
        if series.empty: continue
        latest = float(series.iloc[-1])
        prev   = float(series.iloc[-2]) if len(series)>1 else latest
        change = latest - prev
        try:    val_str = fmt.format(latest)
        except: val_str = f"{latest:.2f}"
        change_color = "#f87171" if change > 0 else "#34d399"
        items.append(html.Div([
            dbc.Row([
                dbc.Col([html.Span(label, style={"fontFamily":"Space Mono","fontSize":"9px","letterSpacing":"0.1em","textTransform":"uppercase","color":"#475569"})], width=7),
                dbc.Col([html.Span(val_str, style={"fontFamily":"Space Mono","fontSize":"12px","fontWeight":"700","color":color})], width=5),
            ]),
            html.Span(f"{change:+.2f}", style={"fontFamily":"Space Mono","fontSize":"9px","color":change_color,"display":"block","textAlign":"right","marginTop":"1px"}),
        ], style={"background":"#0d1220","border":"1px solid rgba(99,179,237,0.08)","borderRadius":"6px","padding":"8px 12px","marginBottom":"6px"}))

    return html.Div(items) if items else html.P("No macro data available.",style={"color":"#475569","fontSize":"11px"})


